sql:
SELECT AVG(salary) AS average_salary
FROM placements
WHERE company_name = 'Google';

SELECT AVG(s.cgpa) AS average_gpa
FROM students s
INNER JOIN placements p ON s.roll_no = p.roll_no;

SELECT university_name
FROM higher_studies
WHERE status = 'Applied';

SELECT name, present_status
FROM students
WHERE present_status IN ('Employment', 'Higher Studies');

SELECT AVG(cgpa) AS average_cgpa
FROM students
WHERE degree = 'BE' AND current_semester = '4th Year' AND gender = 'Male';

external_knowledge:
- 'Top 5' refers to the most recent placements, ordered by the placement date in descending order;
- 'Recently placed' implies that the placement date is on or after January 1, 2020;
- 'Rounded salary' means the salary values are rounded to the nearest whole number.

- "Planted their roots in the professional world" refers to students who have secured placements;
- "Reaching for the stars with further education" refers to students who have applied for higher studies;
- The details include the company name, position, salary, and placement date for placements, and the university name, program name, and application status for higher studies.

- "blossoms" refers to students who have successfully completed their academic journey and are now part of the workforce or pursuing further education;
- "place in the corporate world" refers to students who have been placed in companies;
- "higher pursuits" refers to students who have applied for higher studies.

sql:
SELECT university_name
FROM higher_studies
ORDER BY application_date ASC;

